import WidgetKit
import SwiftUI
import AppIntents

struct MindfulnessIntent: AppIntent {
    static var title: LocalizedStringResource = 'Mindfulness Minutes'
    @Parameter(title: 'Goal (min)') var goal: Int
}

struct MindfulnessWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: 'MindfulnessWidget',
            intent: MindfulnessIntent.self,
            provider: .static
        ) { entry in
            Text("Mindfulness: 20/" + String(entry.goal) + " min")
        }
    }
}

