import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct FitnessRingIntent: AppIntent {
    static var title: LocalizedStringResource = "Fitness Ring"
    @Parameter(title: "Ring Color") var ringColor: String
}

struct FitnessRingWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "FitnessRingWidget",
            intent: FitnessRingIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.ringColor) {
                    content.add(model)
                }
            }
        }
    }
}

